queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?club_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasClubs ?child ; p:hasHigh_Schools ?parent . } GROUP BY ?child }
  ?child p:club_name ?club_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :High_Schools } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?club_name WHERE {
  ?high_schools_clubs a :High_Schools_Clubs .
  ?clubs a :Clubs .
  ?high_schools_clubs p:hasClubs ?clubs .
  ?high_schools a :High_Schools .
  ?high_schools_clubs p:hasHigh_Schools ?high_schools .
  ?high_schools p:name ?name .
  ?clubs p:club_name ?club_name .
} }
  collective: { SELECT ?club_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasClubs ?child ; p:hasHigh_Schools ?parent . } GROUP BY ?child }
  ?child p:club_name ?club_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :High_Schools } }
  FILTER(?nf = ?total)
} }
}
